-- Enterprise Multi-Tenant Runtime Sprint 3 evidence-table completion hotfix
-- Forward-only migration: completes tenant_route_isolation_reviews so it mirrors TENANT_ROUTE_REGISTRY.
-- Does not change Sprint 3 route behavior, route classifications, or tenant schema shape.
-- Does not disable triggers and does not rewrite already-tagged migrations 0028, 0029, or 0030.

on conflict(route_file) do update set
  route_family = excluded.route_family,
  tenant_scope_status = excluded.tenant_scope_status,
  boundary_mode = excluded.boundary_mode,
  evidence_code = excluded.evidence_code,
  notes = excluded.notes,
  updated_at = now();
